// Extract ticket info from email
const input = $input.first().json;
const subject = input.subject || '';
const body = input.text || '';
const from = input.from || '';

// Determine priority based on keywords
const urgentKeywords = ['urgent', 'critical', 'down', 'broken', 'asap'];
const highKeywords = ['important', 'issue', 'problem', 'bug', 'help'];

let priority = 'low';
const lowerSubject = subject.toLowerCase();
const lowerBody = body.toLowerCase();

if (urgentKeywords.some(k => lowerSubject.includes(k) || lowerBody.includes(k))) {
  priority = 'urgent';
} else if (highKeywords.some(k => lowerSubject.includes(k) || lowerBody.includes(k))) {
  priority = 'high';
}

// Categorize ticket
const categories = {
  'billing': ['invoice', 'payment', 'billing', 'charge', 'refund', 'subscription'],
  'technical': ['bug', 'error', 'not working', 'broken', 'issue', 'crash'],
  'account': ['login', 'password', 'access', 'account', 'signup', 'register'],
  'feature': ['feature', 'request', 'suggestion', 'enhancement', 'improvement']
};

let category = 'general';
for (const [cat, keywords] of Object.entries(categories)) {
  if (keywords.some(k => lowerSubject.includes(k) || lowerBody.includes(k))) {
    category = cat;
    break;
  }
}

return [{
  json: {
    ticketId: 'TKT-' + Date.now(),
    subject,
    body: body.substring(0, 500),
    from,
    priority,
    category,
    receivedAt: new Date().toISOString(),
    status: 'open'
  }
}];

// Route to correct agent based on category
const data = $input.first().json;
const category = data.category;
const priority = data.priority;

const agents = {
  'billing': 'billing@company.com',
  'technical': 'tech-support@company.com',
  'account': 'accounts@company.com',
  'feature': 'product@company.com',
  'general': 'support@company.com'
};

const assignedAgent = agents[category] || agents.general;
const slaHours = priority === 'urgent' ? 1 : priority === 'high' ? 4 : 24;

return [{
  json: {
    ...data,
    assignedTo: assignedAgent,
    slaDeadline: new Date(Date.now() + slaHours * 60 * 60 * 1000).toISOString()
  }
}];
